    final result = await H2mBridge.convert(html: '<h1>Title</h1><p>Some <strong>bold</strong> text.</p>', options: _options);
    expect(result.content, contains('Title'));
    expect(result.content, contains('bold'));
    expect(result.content, contains('text.'));
    expect(result.content, isNot(contains('**bold**')));
    expect(result.content, isNot(contains('# Title')));
  });

  test('Aggressive preset removes nav, footer, aside unconditionally', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preprocessing":{"preset":"Aggressive"}}');
    final result = await H2mBridge.convert(html: '<nav>Menu</nav><article><h1>Title</h1><p>Content</p></article><aside>Sidebar</aside><footer>Footer</footer>', options: _options);
    expect(result.content, contains('Title'));
    expect(result.content, contains('Content'));
    expect(result.content, isNot(contains('Menu')));
  });

  test('Disabling preprocessing entirely preserves elements the standard preset would remove', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preprocessing":{"enabled":false}}');
    final result = await H2mBridge.convert(html: '<nav>NavSection</nav><p>Paragraph</p>', options: _options);
    expect(result.content, contains('NavSection'));
    expect(result.content, contains('Paragraph'));
  });

  test('Minimal preset preserves nav, footer, aside', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preprocessing":{"preset":"Minimal"}}');
    final result = await H2mBridge.convert(html: '<nav>Navigation</nav><p>Content</p><footer>Footer</footer>', options: _options);
    expect(result.content, contains('Navigation'));
    expect(result.content, contains('Content'));
    expect(result.content, contains('Footer'));
  });

  test('Forms are removed when remove_forms is true', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preprocessing":{"remove_forms":true}}');
    final result = await H2mBridge.convert(html: '<p>Before</p><form><input type=\'text\'/><button>Submit</button></form><p>After</p>', options: _options);
    expect(result.content, contains('Before'));
    expect(result.content, contains('After'));
    expect(result.content, isNot(contains('Submit')));
  });

  test('Setting remove_navigation to false preserves nav and aside elements', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preprocessing":{"remove_navigation":false}}');
    final result = await H2mBridge.convert(html: '<nav>SiteMenu</nav><main><p>MainContent</p></main><aside>SidebarText</aside>', options: _options);
    expect(result.content, contains('SiteMenu'));
    expect(result.content, contains('MainContent'));
    expect(result.content, contains('SidebarText'));
  });

  test('Iframe tags preserved as raw HTML in output', () async {
    final _options = await createConversionOptionsFromJson(json: '{"preserve_tags":["iframe"]}');
    final result = await H2mBridge.convert(html: '<p>Before</p><iframe src=\'video.html\' width=\'560\'></iframe><p>After</p>', options: _options);
    expect(result.content, contains('Before'));
    expect(result.content, contains('After'));
    expect(result.content, contains('<iframe'));
  });

  test('Images are omitted from output when skipImages is true', () async {
    final _options = await createConversionOptionsFromJson(json: '{"skip_images":true}');
    final result = await H2mBridge.convert(html: '<p>Before <img src=\'test.jpg\' alt=\'photo\'> After</p>', options: _options);
    expect(result.content, contains('Before'));
    expect(result.content, contains('After'));
    expect(result.content, isNot(contains('photo')));
  });

  test('Strip newlines produces single-line paragraphs', () async {
    final _options = await createConversionOptionsFromJson(json: '{"strip_newlines":true}');
    final result = await H2mBridge.convert(html: '<p>First paragraph.</p><p>Second paragraph.</p>', options: _options);
    expect(result.content, contains('First paragraph.'));
    expect(result.content, contains('Second paragraph.'));
  });

  test('Div and span tags stripped but content preserved', () async {
    final _options = await createConversionOptionsFromJson(json: '{"strip_tags":["div","span"]}');
    final result = await H2mBridge.convert(html: '<div class=\'wrapper\'><p>Inside div</p></div><p>Outside <span class=\'hl\'>span text</span></p>', options: _options);
    expect(result.content, contains('Inside div'));
    expect(result.content, contains('span text'));
  });

  test('Strong and em tags use underscore symbol instead of asterisk', () async {
    final _options = await createConversionOptionsFromJson(json: '{"strong_em_symbol":"_"}');
    final result = await H2mBridge.convert(html: '<p><strong>bold</strong> and <em>italic</em></p>', options: _options);
    expect(result.content, contains('__bold__'));
    expect(result.content, contains('_italic_'));
  });

  test('Subscript rendered with tilde symbol', () async {
    final _options = await createConversionOptionsFromJson(json: '{"sub_symbol":"~"}');
    final result = await H2mBridge.convert(html: '<p>H<sub>2</sub>O</p>', options: _options);
    expect(result.content, contains('~2~'));
  });

  test('Superscript rendered with caret symbol', () async {
    final _options = await createConversionOptionsFromJson(json: '{"sup_symbol":"^"}');
    final result = await H2mBridge.convert(html: '<p>x<sup>2</sup></p>', options: _options);
    expect(result.content, contains('^2^'));
  });

  test('Default angle style wraps URLs containing spaces in angle brackets', () async {
    final _options = await createConversionOptionsFromJson(json: '{"url_escape_style":"angle"}');
    final result = await H2mBridge.convert(html: '<a href="/file (1).pdf">file</a>', options: _options);
    expect(result.content, contains('</file (1).pdf>'));
  });

  test('Percent style encodes angle brackets in link URLs from issue 392', () async {
    final _options = await createConversionOptionsFromJson(json: '{"url_escape_style":"percent"}');
    final result = await H2mBridge.convert(html: '<a href="/file (1) <draft>.pdf">file</a>', options: _options);
    expect(result.content, contains('/file%20%281%29%20%3Cdraft%3E.pdf'));
  });

  test('Percent style encodes special characters in image src URLs', () async {
    final _options = await createConversionOptionsFromJson(json: '{"url_escape_style":"percent"}');
    final result = await H2mBridge.convert(html: '<img src="/img (1) <draft>.png" alt="alt">', options: _options);
    expect(result.content, contains('/img%20%281%29%20%3Cdraft%3E.png'));
  });

  test('Percent style encodes spaces and parens in link URLs', () async {
    final _options = await createConversionOptionsFromJson(json: '{"url_escape_style":"percent"}');
    final result = await H2mBridge.convert(html: '<a href="/file (1).pdf">file</a>', options: _options);
    expect(result.content, contains('/file%20%281%29.pdf'));
    expect(result.content, isNot(contains('</')));
  });

  test('Normalized whitespace mode collapses multiple spaces', () async {
    final _options = await createConversionOptionsFromJson(json: '{"whitespace_mode":"Normalized"}');
    final result = await H2mBridge.convert(html: '<p>Text   with    extra   spaces.</p>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Text'));
    expect(result.content, contains('with'));
    expect(result.content, contains('extra'));
    expect(result.content, contains('spaces.'));
  });

  test('Strict whitespace mode preserves whitespace as-is', () async {
    final _options = await createConversionOptionsFromJson(json: '{"whitespace_mode":"Strict"}');
    final result = await H2mBridge.convert(html: '<p>Preserved   spacing.</p>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('Preserved'));
    expect(result.content, contains('spacing.'));
  });

  test('Wrap option disabled preserves long lines without breaking', () async {
    final _options = await createConversionOptionsFromJson(json: '{"wrap":false}');
    final result = await H2mBridge.convert(html: '<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>', options: _options);
    expect(result.content, contains('This is a long paragraph that should not be wrapped at all because wrapping is disabled.'));
  });

  test('Wrap option enabled with custom width wraps long lines', () async {
    final _options = await createConversionOptionsFromJson(json: '{"wrap":true,"wrap_width":40}');
    final result = await H2mBridge.convert(html: '<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>', options: _options);
    expect(result.content, isNotNull);
    expect(result.content, contains('This is a long paragraph'));
  });

}
